var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"아앗, 전대원 분들! 그리로 가면 안 되죠!","JPN":"ああっ、戦隊員の皆さん！　そっちじゃないです！","ENG":"Ahh, everyone! Don’t go that way!","TWN":"欸欸，各位戰隊員！不是往那裡啦！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"A2! A2 좌표라고요!","JPN":"A2！　A2座標ですってば！","ENG":"A2! Coordinates A2!","TWN":"是A2！A2座標才對！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그렇죠! 역시 우리 전대원 분들! 만세!","JPN":"それです！　さすがは皆さん！　やっほー！","ENG":"That’s it! Nice! As expected of our Division soldiers! Hooray!","TWN":"沒錯！不愧是我們的戰隊員！萬歲！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"새삼 느끼지만, 기술력이 굉장하네……. 거의 사람이잖아.","JPN":"今更だけど、すごい技術力だね……ほぼ人間じゃないの。","ENG":"Such an amazing technology… She's practically a real person.\\n\\n","TWN":"再次感受到科技的厲害……跟人根本沒什麼兩樣嘛！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런데 레버넌트 씨, 지금 뭐 하는 거예요?","JPN":"ところでレヴナントさん、今何やってるんですか？","ENG":"Wait, Revenant, what are you doing?","TWN":"不過亡靈小姐，請問你現在在做什麼？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"잠깐만……. 거의 다 됐으니까…….","JPN":"ちょっと待って……もうすぐだから……","ENG":"Just a moment... Almost got it...","TWN":"等我一下……就快好了……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"앗? 자, 잠깐만요! 그쪽 회로는 함부로 건드리시면……!","JPN":"えっ？　ま、待ってください！　そっちの回路を勝手にいじったら……！","ENG":"Ah? Wait! If you mess with that circuit...!","TWN":"嗯？喂，快住手！那邊的線路不能隨便亂碰……！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"역시 인공지능의 수준은 높아도 함선 구조 자체는 제식이네.","JPN":"やっぱり人工知能のレベルは高くても、艦船の構造自体は他の機体と同じね。","ENG":"As expected, even if the A.I. tech is this advanced, the ship structure itself is pretty standard.","TWN":"就算有很高的人工智慧，但艦船本身的結構是固定的。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"인공지능이 멎었잖아요?! 어서 원래대로 돌려 두세요!","JPN":"人工知能が止まってるじゃないですか！？　早く元どおりに戻してください！","ENG":"You disabled the A.I.?! Hey, turn it back on!","TWN":"人工智慧不說話咧？！你快點把它弄回去啦！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"안 돼. 애초에 내가 나갔다는 걸 보고할 수 없게 한 거니까.","JPN":"ダメ。元々私が出たことを報告できなくするためにやったんだから。","ENG":"No. I don’t want it to be able to report that I’ve left.","TWN":"不行，我就是要讓她不能打小報告，說我跑出去。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"무슨 말이에요? 나가다니 어디로?","JPN":"どういうことですか？　出るってどこに？","ENG":"What are you talking about? Where are you going?","TWN":"你在說什麼？你要去哪裡？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"전술 현황판을 봐 봐. 이유는 모르겠지만 아까부터 알렉스 씨의 신호가 앞으로 나아가지 못하고 있어.","JPN":"戦術の現状を見てみて。理由はわからないけど、さっきからアレックスさんの信号が前に進めずにいるの。","ENG":"Look at the tactical status board. I don’t know why, but Alex’s signal hasn’t moved for a while.","TWN":"你看這個戰術儀表板，從剛剛開始，不知道為什麼，雅蕾克絲的訊號就無法再往前。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"더 늦었다간 중앙대로에 포격이 떨어질 거야.","JPN":"遅くなると中央通りに砲撃が落ちるよ。","ENG":"If we’re too late, the main street will be battered down.","TWN":"不快一點的話，砲彈會打到中央大道的！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래서 막으러 가겠다고요?","JPN":"だから止めに行くって言ってるんですか？","ENG":"So you’re going to go stop it?","TWN":"所以你要去擋砲彈？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……영웅 나셨네, 진짜. 자의식이 너무 비대한 거 아니에요?","JPN":"……ヒーローじゃないっつーの、まったく。自意識過剰じゃないですか？","ENG":"...You really have a savior complex, don’t you? Isn’t your sense of responsibility towards others a little too high?","TWN":"……有夠逞英雄的，你是不是太高估你自己啦？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"정부군이 저것들을 가만 놔두겠어요? 국가 기관을 너무 물로 보는 거 아니냐고요!","JPN":"政府軍があれを放っておくわけないでしょう？　国家機関はバカじゃないんです！","ENG":"You think the government forces will just let them get away with that? You think the government is a complete joke?","TWN":"你覺得政府軍會坐視不管嗎？未免也太小看國家機關！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하지만 내버려 두면 피해가 커져.","JPN":"でも放っておいたら被害が大きくなるよ。","ENG":"But if we do nothing, the damage will be even worse.","TWN":"但是再不出手的話，恐怕會造成更大的傷害！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};